@IgnoreAuth
@RequestMapping("/login")
public R login(String username, String password,
               String captcha, HttpServletRequest request) {
    YonghuEntity yonghu = yonghuService.selectOne(
        new EntityWrapper<YonghuEntity>()
            .eq("username", username));
    if (yonghu == null || !yonghu.getPassword().equals(password))
        return R.error("账号或密码不正确");
    String token = tokenService.generateToken(
        yonghu.getId(), username, "yonghu", "用户");
    return R.ok().put("token", token);
}

@IgnoreAuth
@RequestMapping("/detail/{id}")
public R detail(@PathVariable("id") Long id,
                HttpServletRequest request) {
    CaipinEntity caipin = caipinService.selectById(id);
    if (caipin != null) {
        // 浏览次数加1
        caipin.setCaipinClicknum(
            caipin.getCaipinClicknum() + 1);
        caipinService.updateById(caipin);
        CaipinView view = new CaipinView();
        BeanUtils.copyProperties(caipin, view);
        dictionaryService.dictionaryConvert(view, request);
        return R.ok().put("data", view);
    }
    return R.error(511, "查不到数据");
}

@RequestMapping("/add")
public R add(@RequestBody CaipinOrderEntity caipinOrder,
             HttpServletRequest request) {
    CaipinEntity caipin = caipinService.selectById(
        caipinOrder.getCaipinId());
    if (caipin == null)
        return R.error(511, "查不到该菜品");
    if (caipin.getCaipinKucunNumber() - caipinOrder.getBuyNumber() < 0)
        return R.error(511, "购买数量不能大于库存数量");
    Integer userId = (Integer) request.getSession()
        .getAttribute("userId");
    YonghuEntity yonghu = yonghuService.selectById(userId);
    double balance = yonghu.getNewMoney()
        - caipin.getCaipinNewMoney() * caipinOrder.getBuyNumber();
    if (balance < 0)
        return R.error(511, "余额不够支付");
    // 扣减库存、余额，累加积分
    caipin.setCaipinKucunNumber(
        caipin.getCaipinKucunNumber() - caipinOrder.getBuyNumber());
    caipinService.updateById(caipin);
    yonghu.setNewMoney(balance);
    Double buyJifen = new BigDecimal(caipin.getCaipinPrice())
        .multiply(new BigDecimal(caipinOrder.getBuyNumber()))
        .doubleValue();
    yonghu.setYonghuSumJifen(
        yonghu.getYonghuSumJifen() + buyJifen);
    yonghu.setYonghuNewJifen(
        yonghu.getYonghuNewJifen() + buyJifen);
    // 会员等级自动评定
    if (yonghu.getYonghuSumJifen() < 10000)
        yonghu.setHuiyuandengjiTypes(1);
    else if (yonghu.getYonghuSumJifen() < 100000)
        yonghu.setHuiyuandengjiTypes(2);
    else
        yonghu.setHuiyuandengjiTypes(3);
    yonghuService.updateById(yonghu);
    caipinOrder.setCaipinOrderTypes(1);
    caipinOrder.setCaipinOrderTruePrice(
        caipin.getCaipinNewMoney() * caipinOrder.getBuyNumber());
    caipinOrderService.insert(caipinOrder);
    return R.ok();
}

@RequestMapping("/save")
public R save(@RequestBody CaipinEntity caipin,
              HttpServletRequest request) {
    Wrapper<CaipinEntity> queryWrapper =
        new EntityWrapper<CaipinEntity>()
            .eq("caipin_name", caipin.getCaipinName())
            .eq("caipin_delete", 1);
    CaipinEntity existing = caipinService.selectOne(queryWrapper);
    if (existing != null)
        return R.error(511, "该菜品名称已存在");
    caipin.setCaipinClicknum(1);
    caipin.setShangxiaTypes(1);
    caipin.setCaipinDelete(1);
    caipin.setCreateTime(new Date());
    caipinService.insert(caipin);
    return R.ok();
}

@RequestMapping("/refund")
public R refund(Integer id, HttpServletRequest request) {
    CaipinOrderEntity order = caipinOrderService.selectById(id);
    CaipinEntity caipin = caipinService.selectById(
        order.getCaipinId());
    YonghuEntity yonghu = yonghuService.selectById(
        (Integer) request.getSession().getAttribute("userId"));
    // 查询会员折扣
    Double zhekou = 1.0;
    DictionaryEntity dict = dictionaryService.selectOne(
        new EntityWrapper<DictionaryEntity>()
            .eq("dic_code", "huiyuandengji_types")
            .eq("code_index", yonghu.getHuiyuandengjiTypes()));
    if (dict != null)
        zhekou = Double.valueOf(dict.getBeizhu());
    // 退还余额，扣减积分，恢复库存
    Double refundMoney = caipin.getCaipinNewMoney()
        * order.getBuyNumber() * zhekou;
    yonghu.setNewMoney(yonghu.getNewMoney() + refundMoney);
    Double buyJifen = new BigDecimal(caipin.getCaipinPrice())
        .multiply(new BigDecimal(order.getBuyNumber()))
        .doubleValue();
    yonghu.setYonghuSumJifen(
        yonghu.getYonghuSumJifen() - buyJifen);
    yonghu.setYonghuNewJifen(
        yonghu.getYonghuNewJifen() - buyJifen);
    caipin.setCaipinKucunNumber(
        caipin.getCaipinKucunNumber() + order.getBuyNumber());
    order.setCaipinOrderTypes(2);
    caipinOrderService.updateById(order);
    yonghuService.updateById(yonghu);
    caipinService.updateById(caipin);
    return R.ok();
}
